import { BookingEntity } from "@/domain/entities/bookingEntity";
import { BaseRepository } from "../baseRepository";
import { QueryFilter } from "mongoose";
import {
  BookingDocument,
  BookingModel,
} from "@/framework/database/model/bookingModel";
import { IBookingRepository } from "@/domain/interface/repository/IBookingRepository";
import { User } from "@/domain/entities/userEntities";
import { PackageEntity } from "@/domain/entities/packageEntity";
import { BookingStatus } from "@/constants/bookingStatus";
import { PackageModel } from "@/framework/database/model/packageModel";

export class BookingRepository
  extends BaseRepository<BookingEntity, BookingDocument>
  implements IBookingRepository {
  constructor() {
    super(BookingModel);
  }
  async findByStripeSessionId(
    sessionId: string,
  ): Promise<BookingEntity | null> {
    const doc = await this.model
      .findOne({ stripeSessionId: sessionId })
      .populate("packageId")
      .populate("userId")
      .exec();
    return doc ? this.mapToEntity(doc) : null;
  }
  async findByUser(userId: string): Promise<BookingEntity[]> {
    const docs = await this.model
      .find({ userId })
      .populate("packageId")
      .sort({ createdAt: -1 })
      .exec();
    return docs.map((item) => this.mapToEntity(item));
  }

  async updateStatus(
    id: string,
    status: BookingStatus,
  ): Promise<BookingEntity | null> {
    const updated = await this.model
      .findByIdAndUpdate(id, { $set: { status } }, { new: true })
      .exec();
    return updated ? this.mapToEntity(updated) : null;
  }
  async checkAvailability(packageId: string, date: Date): Promise<boolean> {
    const existing = await this.model.findOne({
      packageId,
      bookingDate: date,
      status: { $ne: BookingStatus.CANCELLED },
    });
    return !existing;
  }
  async findByCreatorId(creatorId: string): Promise<BookingEntity[]> {
    const packages = await PackageModel.find({ creatorId }).select("_id");
    const packageIds = packages.map(p => p._id.toString());
    const docs = await this.model
      .find({ packageId: { $in: packageIds } } as QueryFilter<BookingDocument>)
      .populate("packageId")
      .populate("userId")
      .sort({ bookingDate: 1 })
      .exec();
    return docs.map((item) => this.mapToEntity(item));
  }

  async findBookingsForPaymentRelease(date: Date): Promise<BookingEntity[]> {
    const docs = await this.model.find({
      bookingDate: { $lt: date },
      status: BookingStatus.COMPLETED,
      paymentStatus: "held"
    }).exec();
    return docs.map(doc => this.mapToEntity(doc));
  }

  async updatePaymentStatus(id: string, paymentStatus: "held" | "released" | "refunded" | "partially_refunded"): Promise<BookingEntity | null> {
    const updated = await this.model.findByIdAndUpdate(id, { $set: { paymentStatus } }, { new: true }).exec();
    return updated ? this.mapToEntity(updated) : null;
  }

  protected mapToEntity(doc: BookingDocument): BookingEntity {
    const isPackagePopulated = doc.packageId && typeof doc.packageId === 'object' && 'title' in doc.packageId;
    const isUserPopulated = doc.userId && typeof doc.userId === 'object' && 'name' in doc.userId;

    return {
      id: doc._id.toString(),
      userId: isUserPopulated ? (doc.userId as User) : doc.userId.toString(),
      packageId: isPackagePopulated ? (doc.packageId as PackageEntity) : doc.packageId.toString(),
      amount: doc.amount,
      currency: doc.currency as "inr",
      status: doc.status,
      stripeSessionId: doc.stripeSessionId,
      bookingDate: doc.bookingDate,
      location: doc.location,
      paymentStatus: (doc as any).paymentStatus,
      createdAt: doc.createdAt,
      updatedAt: doc.updatedAt,
    };
  }
}

import { PaginatedResult } from "@/domain/types/paginationTypes";
import { User } from "../../../domain/entities/userEntities";
import { UserModel, IUserModel } from "../../../framework/database/model/userModel";
import { paginateMongo } from "@/utils/pagination";
import { BaseRepository } from "../baseRepository";
import { IUserRepository } from "@/domain/interface/repository/IUserRepository";
import { Filter } from "mongodb";

export class UserRepository extends BaseRepository<User, IUserModel> implements IUserRepository {
  constructor() {
    super(UserModel);
  }




  async findByEmail(email: string): Promise<User | null> {
    const user = await this.model.findOne({ email });
    return user ? this.mapToEntity(user) : null;
  }

  async createUser(user: Omit<User, "_id">): Promise<User> {
    const created = await this.model.create(user as unknown as Omit<IUserModel, keyof Document>);
    return this.mapToEntity(created as IUserModel);
  }

  async updatePassword(email: string, hashedPassword: string): Promise<void> {
    await this.model.updateOne({ email }, { $set: { password: hashedPassword } });
  }

  async findAllUsers(page: number, limit: number, search?: string, status?: string): Promise<PaginatedResult<User>> {
    const query: Filter<IUserModel> = { role: "user" };
    if (status && status !== "all") {
      query.status = status as "active" | "blocked";
    }
    if (search) {
      query.$or = [
        { name: { $regex: search, $options: "i" } },
        { email: { $regex: search, $options: "i" } }
      ];
    }
    const result = await paginateMongo(this.model, query, page, limit, { select: "-password", sort: { createdAt: -1 } });
    return { ...result, data: result.data.map((user: IUserModel) => this.mapToEntity(user)) };
  }

  async updateUserStatus(userId: string, status: "active" | "blocked"): Promise<void> {
    await this.model.updateOne({ _id: userId }, { $set: { status: status } });
  }

  async findByPhone(phone: string | undefined): Promise<User | null> {
    if (!phone) return null;
    const user = await this.model.findOne({ phone });
    return user ? this.mapToEntity(user) : null;
  }

  async editProfile(userId: string, data: { name?: string; phone?: string; image?: string; }): Promise<User | null> {
    const user = await this.model.findByIdAndUpdate(userId, { $set: data }, { new: true }).select("-password");
    return user ? this.mapToEntity(user) : null;
  }

  async findAdminId(): Promise<string | null> {
    const admin = await this.model.findOne({ role: "admin" }).select("_id").lean();
    return admin ? (admin as any)._id.toString() : null;
  }

  protected mapToEntity(doc: IUserModel): User {
    return {
      _id: doc._id.toString(),
      name: doc.name,
      email: doc.email,
      password: doc.password,
      phone: doc.phone,
      googleId: doc.googleId,
      image: doc.image,
      status: doc.status,
      role: doc.role,
      googleVerified: doc.googleVerified,
      createdAt: doc.createdAt,
    };
  }
}

import { IWalletRepository } from "@/domain/interface/repository/IWalletRepository";
import { Wallet, WalletOwnerType } from "@/domain/entities/walletEntity";
import { WalletTransaction } from "@/domain/entities/walletTransactionEntity";
import { WalletModel } from "@/framework/database/schema/walletSchema";
import { WalletTransactionModel } from "@/framework/database/schema/walletTransactionSchema";
import mongoose from "mongoose";

export class WalletRepository implements IWalletRepository {
    async getWallet(ownerId: string, ownerType: WalletOwnerType): Promise<Wallet> {
        let wallet = await WalletModel.findOne({ ownerId, ownerType });
        if (!wallet) {
            wallet = await WalletModel.create({ ownerId, ownerType, balance: 0 });
        }
        return {
            id: wallet._id.toString(),
            ownerId: wallet.ownerId,
            ownerType: wallet.ownerType as WalletOwnerType,
            balance: wallet.balance,
            lastUpdated: wallet.lastUpdated,
        };
    }

    async updateBalance(
        ownerId: string,
        ownerType: WalletOwnerType,
        amount: number,
        transactionData: Omit<WalletTransaction, "id" | "walletId" | "timestamp">
    ): Promise<void> {
        try {
            // Find or create wallet with balance update
            const wallet = await WalletModel.findOneAndUpdate(
                { ownerId, ownerType },
                { $inc: { balance: amount }, lastUpdated: new Date() },
                { upsert: true, new: true }
            );

            // Record transaction
            await WalletTransactionModel.create({
                ...transactionData,
                walletId: wallet._id,
            });

        } catch (error) {
            console.error("WalletRepository updateBalance error:", error);
            throw error;
        }
    }

    async getTransactions(walletId: string, search?: string, source?: string, page: number = 1, limit: number = 10): Promise<{ transactions: WalletTransaction[]; total: number }> {
        const query: any = { walletId: new mongoose.Types.ObjectId(walletId) };

        if (search && search.trim() !== "") {
            const searchRegex = { $regex: search.trim(), $options: "i" };
            query.$or = [
                { relatedName: searchRegex },
                { description: searchRegex }
            ];
        }

        if (source && source.trim() !== "") {
            query.source = source.trim();
        }

        const skip = (page - 1) * limit;
        const [transactions, total] = await Promise.all([
            WalletTransactionModel.find(query).sort({ timestamp: -1 }).skip(skip).limit(limit),
            WalletTransactionModel.countDocuments(query)
        ]);

        return {
            transactions: transactions.map((t) => ({
                id: t._id.toString(),
                walletId: t.walletId.toString(),
                amount: t.amount,
                type: t.type as any,
                description: t.description,
                source: t.source as any,
                sourceId: t.sourceId,
                relatedName: (t as any).relatedName,
                timestamp: t.timestamp,
            })),
            total
        };
    }
}

