import { NotificationType } from "@/domain/entities/notificationEntity";
import { ISendNotificationUseCase } from "@/domain/interface/notification/ISendNotificationUseCase";
import { IBookingRepository } from "@/domain/interface/repository/IBookingRepository";
import { IComplaintRepository } from "@/domain/interface/repository/IComplaintRepository";
import { IWalletRepository } from "@/domain/interface/repository/IWalletRepository";
import { ComplaintEntity } from "@/domain/entities/complaintEntity";
import { IRejectComplaintUseCase } from "@/domain/interface/admin/complaint/IRejectComplaintUseCase";

export class RejectComplaintUseCase implements IRejectComplaintUseCase {
  constructor(
    private complaintRepository: IComplaintRepository,
    private bookingRepository: IBookingRepository,
    private walletRepository: IWalletRepository,
    private sendNotificationUseCase: ISendNotificationUseCase
  ) {}

  async rejectComplaint(complaintId: string, adminComment: string): Promise<ComplaintEntity | null> {
    const complaint = await this.complaintRepository.findById(complaintId);
    if (!complaint) throw new Error("Complaint not found");
    if (complaint.status !== "pending") throw new Error("Complaint already processed");

    const booking = await this.bookingRepository.findById(complaint.bookingId);
    if (!booking) throw new Error("Booking not found");

    // In case of rejection (dismissal), the creator gets the payment
    const creatorId = typeof complaint.creatorId === 'string' 
      ? complaint.creatorId 
      : (complaint.creatorId as any)._id;

    const totalAmount = booking.amount;
    const commission = Math.round(totalAmount * 0.2);
    const creatorAmount = totalAmount - commission;

    // 1. Debit Admin Wallet (Only the creator's share, admin retains commission)
    await this.walletRepository.updateBalance("admin", "admin", -creatorAmount, {
      amount: creatorAmount,
      type: "debit",
      description: `Payout for booking ${booking.id || (booking as any).id} - Complaint Rejected (Total: ₹${totalAmount}, Commission: ₹${commission})`,
      source: "booking",
      sourceId: complaint.bookingId,
      relatedName: "creator_payout"
    });

    // 2. Credit Creator Wallet
    await this.walletRepository.updateBalance(creatorId, "creator", creatorAmount, {
      amount: creatorAmount,
      type: "credit",
      description: `Payment received for booking ${booking.id || (booking as any).id} - Complaint Rejected (After 20% admin commission)`,
      source: "booking",
      sourceId: complaint.bookingId,
    });

    complaint.status = "dismissed";
    complaint.adminComment = adminComment;
    
    // 3. Update Booking Payment Status
    await this.bookingRepository.updatePaymentStatus(complaint.bookingId, "released");
    
    const updatedComplaint = await this.complaintRepository.update(complaint);

    // Send notification to user
    try {
      const userId = typeof complaint.userId === 'string' ? complaint.userId : (complaint.userId as any)._id?.toString();
      if (userId) {
        await this.sendNotificationUseCase.sendNotification({
          recipientId: userId,
          type: NotificationType.REPORT,
          title: "Complaint Update - Rejected",
          message: `Your complaint for booking ${booking.id || (booking as any).id} has been reviewed and rejected. Admin feedback: ${adminComment}`,
          isRead: false,
          metadata: { 
            complaintId: updatedComplaint?._id?.toString(), 
            status: updatedComplaint?.status, 
            bookingId: booking.id || (booking as any).id || (booking as any)._id?.toString()
          }
        });
      }

      // Also notify creator
      const creatorIdStr = typeof creatorId === 'string' ? creatorId : (creatorId as any)._id?.toString();
      if (creatorIdStr) {
        await this.sendNotificationUseCase.sendNotification({
          recipientId: creatorIdStr,
          type: NotificationType.REPORT,
          title: "Complaint Update - Dismissed",
          message: `A complaint for booking ${booking.id || (booking as any).id} has been dismissed in your favor. Payment released. Admin feedback: ${adminComment}`,
          isRead: false,
          metadata: { 
            complaintId: updatedComplaint?._id?.toString(), 
            status: updatedComplaint?.status, 
            bookingId: booking.id || (booking as any).id || (booking as any)._id?.toString()
          }
        });
      }
    } catch (error) {
      console.error("Failed to send notification:", error);
    }

    return updatedComplaint;
  }
}

import { NotificationType } from "@/domain/entities/notificationEntity";
import { ISendNotificationUseCase } from "@/domain/interface/notification/ISendNotificationUseCase";
import { IBookingRepository } from "@/domain/interface/repository/IBookingRepository";
import { IComplaintRepository } from "@/domain/interface/repository/IComplaintRepository";
import { IWalletRepository } from "@/domain/interface/repository/IWalletRepository";
import { ComplaintEntity } from "@/domain/entities/complaintEntity";
import { IResolveComplaintUseCase } from "@/domain/interface/admin/complaint/IResolveComplaintUseCase";

export class ResolveComplaintUseCase implements IResolveComplaintUseCase {
  constructor(
    private complaintRepository: IComplaintRepository,
    private bookingRepository: IBookingRepository,
    private walletRepository: IWalletRepository,
    private sendNotificationUseCase: ISendNotificationUseCase
  ) {}

  async resolveComplaint(complaintId: string, action: "resolve" | "dismiss", adminComment: string): Promise<ComplaintEntity | null> {
    const complaint = await this.complaintRepository.findById(complaintId);
    if (!complaint) throw new Error("Complaint not found");
    if (complaint.status !== "pending") throw new Error("Complaint already processed");

    const booking = await this.bookingRepository.findById(complaint.bookingId);
    if (!booking) throw new Error("Booking not found");

    if (action === "resolve") {
      const userId = typeof complaint.userId === 'string' ? complaint.userId : (complaint.userId as any)._id;
      
      // Debit Admin Wallet (Full amount refunded to user)
      await this.walletRepository.updateBalance("admin", "admin", -booking.amount, {
        amount: booking.amount,
        type: "debit",
        description: `Refund for booking ${booking.id} - Complaint Resolved`,
        source: "refund",
        sourceId: complaint.bookingId,
        relatedName: "user_refund"
      });

      // Credit User Wallet (100% of the booking amount returned to user)
      await this.walletRepository.updateBalance(userId, "user", booking.amount, {
        amount: booking.amount,
        type: "credit",
        description: `Refund for booking ${booking.id} - Complaint Resolved`,
        source: "refund",
        sourceId: complaint.bookingId,
      });

      complaint.status = "resolved";
      await this.bookingRepository.updatePaymentStatus(complaint.bookingId, "refunded");
    } else {
      const creatorId = typeof complaint.creatorId === 'string' ? complaint.creatorId : (complaint.creatorId as any)._id;
      
      const totalAmount = booking.amount;
      const commission = Math.round(totalAmount * 0.2);
      const creatorAmount = totalAmount - commission;

      // 1. Debit Admin Wallet (Only the creator's share, admin retains commission)
      await this.walletRepository.updateBalance("admin", "admin", -creatorAmount, {
        amount: creatorAmount,
        type: "debit",
        description: `Payment release for booking ${booking.id} - Complaint Dismissed (Total: ₹${totalAmount}, Commission: ₹${commission})`,
        source: "booking",
        sourceId: complaint.bookingId,
        relatedName: "creator_payout"
      });

      // 2. Credit Creator Wallet
      await this.walletRepository.updateBalance(creatorId, "creator", creatorAmount, {
        amount: creatorAmount,
        type: "credit",
        description: `Payment for booking ${booking.id} - Complaint Dismissed (After 20% admin commission)`,
        source: "booking",
        sourceId: complaint.bookingId,
      });

      complaint.status = "dismissed";
      await this.bookingRepository.updatePaymentStatus(complaint.bookingId, "released");
    }

    complaint.adminComment = adminComment;
    const updatedComplaint = await this.complaintRepository.update(complaint);

    // Send notifications
    try {
      const userIdStr = typeof complaint.userId === 'string' ? complaint.userId : (complaint.userId as any)._id?.toString();
      if (userIdStr) {
        await this.sendNotificationUseCase.sendNotification({
          recipientId: userIdStr,
          type: NotificationType.REPORT,
          title: action === "resolve" ? "Complaint Resolved - Refund Issued" : "Complaint Update",
          message: action === "resolve" 
            ? `Your complaint for booking ${booking.id || (booking as any)._id} has been resolved and a refund of ₹${booking.amount} has been credited to your wallet. Admin feedback: ${adminComment}`
            : `Your complaint for booking ${booking.id || (booking as any)._id} has been reviewed. Status: Dismissed. Admin feedback: ${adminComment}`,
          isRead: false,
          metadata: { 
            complaintId: updatedComplaint?._id?.toString(), 
            status: updatedComplaint?.status, 
            bookingId: booking.id || (booking as any)._id?.toString() || (booking as any).id 
          }
        });
      }

      const creatorIdStr = typeof complaint.creatorId === 'string' ? complaint.creatorId : (complaint.creatorId as any)._id?.toString();
      if (creatorIdStr) {
        await this.sendNotificationUseCase.sendNotification({
          recipientId: creatorIdStr,
          type: NotificationType.REPORT,
          title: action === "resolve" ? "Complaint Update - Refund Processed" : "Complaint Dismissed - Payment Released",
          message: action === "resolve"
            ? `A complaint for booking ${booking.id || (booking as any)._id} was resolved. Payment was refunded to the user.`
            : `A complaint for booking ${booking.id || (booking as any)._id} has been dismissed. Payment released to your wallet.`,
          isRead: false,
          metadata: { 
            complaintId: updatedComplaint?._id?.toString(), 
            status: updatedComplaint?.status, 
            bookingId: booking.id || (booking as any)._id?.toString() || (booking as any).id 
          }
        });
      }
    } catch (error) {
      console.error("Failed to send notification:", error);
    }

    return updatedComplaint;
  }
}

import { ConversationEntity } from "@/domain/entities/conversationEntity";
import { IChatRepository } from "@/domain/interface/repository/IChatRepository ";
import { IBookingRepository } from "@/domain/interface/repository/IBookingRepository";
import { IPackageRepository } from "@/domain/interface/repository/IPackageRepository";
import { AppError } from "@/domain/errors/appError";
import { StatusCode } from "@/constants/statusCodes";

export class CreateConversationUseCase {
    constructor(
        private _chatRepo: IChatRepository,
        private _bookingRepo: IBookingRepository,
        private _packageRepo: IPackageRepository
    ) { }

    async execute(bookingId: string): Promise<ConversationEntity> {
        // 1. Check if conversation already exists
        const existing = await this._chatRepo.getConversationByBooking(bookingId);
        if (existing) return existing;

        // 2. Load the booking to get userId and packageId (and from that, creatorId)
        const booking = await this._bookingRepo.findById(bookingId);
        if (!booking) throw new AppError("Booking not found", StatusCode.NOT_FOUND);

        const packageId = typeof booking.packageId === "string"
            ? booking.packageId
            : (booking.packageId as any)._id?.toString() || booking.packageId?.toString();

        const pkg = await this._packageRepo.findById(packageId);
        if (!pkg) throw new AppError("Package not found", StatusCode.NOT_FOUND);

        const creatorId = typeof pkg.creatorId === "string"
            ? pkg.creatorId
            : (pkg.creatorId as any)._id?.toString() || pkg.creatorId?.toString();

        const userId = typeof booking.userId === "string"
            ? booking.userId
            : (booking.userId as any)._id?.toString() || booking.userId?.toString();

        // 3. Create the conversation
        await this._chatRepo.createConversation({
            bookingId: bookingId as any,
            participants: [userId as any, creatorId as any],
            lastMessage: "Booking confirmed! You can now start chatting.",
            lastMessageAt: new Date(),
        });

        // 4. Return the populated version
        const newConversation = await this._chatRepo.getConversationByBooking(bookingId);
        if (!newConversation) throw new AppError("Failed to create conversation", StatusCode.INTERNAL_SERVER_ERROR);

        return newConversation;
    }
}

import { MessageEntity } from "@/domain/entities/messageEntity";
import { ISendMessageUseCase } from "@/domain/interface/chat/ISendMessageUseCase";
import { IChatRepository } from "@/domain/interface/repository/IChatRepository ";
import { ISendNotificationUseCase } from "@/domain/interface/notification/ISendNotificationUseCase";
import { NotificationType } from "@/domain/entities/notificationEntity";
import { IUserRepository } from "@/domain/interface/repository/IUserRepository";
import { ICreatorRepository } from "@/domain/interface/repository/ICreatorRepository";

export class SendMessageUseCase implements ISendMessageUseCase {
    constructor(
        private _chatRepo: IChatRepository,
        private _sendNotificationUseCase: ISendNotificationUseCase,
        private _userRepo: IUserRepository,
        private _creatorRepo: ICreatorRepository
    ) {}

    async sendMessage(data: { conversationId: string; senderId: string; message: string; recipientId: string }): Promise<MessageEntity> {
        const message = await this._chatRepo.saveMessage({
            conversationId: data.conversationId as any,
            senderId: data.senderId as any,
            message: data.message
        });

        await this._chatRepo.updateConversationLastMessage(data.conversationId, data.message);

        // Fetch sender's name for notification via repositories
        const [user, creator] = await Promise.all([
            this._userRepo.findById(data.senderId),
            this._creatorRepo.findById(data.senderId)
        ]);

        const senderName = user?.name || creator?.fullName || "Someone";

        await this._sendNotificationUseCase.sendNotification({
            recipientId: data.recipientId,
            senderId: data.senderId,
            type: NotificationType.CHAT,
            title: `New Message from ${senderName}`,
            message: data.message,
            metadata: { conversationId: data.conversationId },
            isRead: false
        });

        return message;
    }
}

import { PackageMapper } from "@/application/mapper/user/packageMapper";
import { PackageResponseDto } from "@/domain/dto/user/packageResponseDto";
import { PackageEntity } from "@/domain/entities/packageEntity";
import { IEditPackageUseCase } from "@/domain/interface/creator/package/IEditPackageUseCase";
import { IPackageRepository } from "@/domain/interface/repository/IPackageRepository";

export class EditPackageUseCase implements IEditPackageUseCase {
  constructor(
    private _packageRepo: IPackageRepository
  ) {}

  async editPackage(
    packageId: string,
    creatorId: string,
    data: Partial<PackageEntity>
  ): Promise<PackageResponseDto> {
    const existingPackage = await this._packageRepo.findById(packageId);

    if (!existingPackage) {
      throw new Error("Package not found");
    }


    const existingCreatorId = (typeof existingPackage.creatorId === 'object' && existingPackage.creatorId !== null)
      ? (existingPackage.creatorId as any)._id?.toString()
      : existingPackage.creatorId.toString();

    if (existingCreatorId !== creatorId.toString()) {
      throw new Error("Unauthorized: You can only edit your own packages");
    }

    const updateData: Partial<PackageEntity> = {
      ...(data.title && { title: data.title }),
      ...(data.description && { description: data.description }),
      ...(data.price !== undefined && { price: data.price }),
      ...(data.category && { category: data.category }),
      ...(data.images && { images: data.images }),
      ...(data.locations && { locations: data.locations }),
    };

    const updatedPackage = await this._packageRepo.update(packageId, updateData);

    if (!updatedPackage) {
      throw new Error("Failed to update package");
    }

    return PackageMapper.toDto(updatedPackage);
  }
}

import { CreatorMapper } from "@/application/mapper/creator/creatorMapper";
import { CreatorResponseDto } from "@/domain/dto/creator/creatorResponseDto";
import { IeditCreatorProfileUseCase } from "@/domain/interface/creator/profile/IEditCreatorUseCase";
import { ICreatorRepository } from "@/domain/interface/repository/ICreatorRepository";

export class EditCreatorProfileUseCase implements IeditCreatorProfileUseCase {
    constructor(
        private _creatorRepo: ICreatorRepository
    ) {}
    async editProfile(creatorId: string, data: any): Promise<CreatorResponseDto | null> {
        if (!creatorId) throw new Error("Creator id is required")

        if (!data) throw new Error("data is not getting")
        if (data.phone) {
            const trimmed = data.phone.trim()
            const existingPhone = await this._creatorRepo.findByPhone(trimmed)
            if (existingPhone && (existingPhone as any)._id?.toString() !== creatorId) {
                throw new Error("Mobile number is already used")
            }
        }

        const updatedCreator = await this._creatorRepo.updateProfile(creatorId, data)
        return updatedCreator ? CreatorMapper.toDto(updatedCreator) : null;
    }
}

import { ICreatorSubscriptionWebhookUseCase } from "@/domain/interface/creator/payment/ICreatorSubscriptionWebhookUseCase";
import { ICreatorRepository } from "@/domain/interface/repository/ICreatorRepository";
import { IUserRepository } from "@/domain/interface/repository/IUserRepository";
import { ISubscriptionRepository } from "@/domain/interface/repository/ISubscriptionRepositories";
import { IStripeService } from "@/domain/interface/service/IStripeService";
import { ICreditWalletUseCase } from "@/domain/interface/wallet/ICreditWalletUseCase";
import { IMailService } from "@/domain/interface/service/IMailServices";
import { renderTemplate } from "@/utils/renderTemplates";
import { logger } from "@/utils/logger";
import path from "node:path";
import Stripe from "stripe";

import { ISendNotificationUseCase } from "@/domain/interface/notification/ISendNotificationUseCase";
import { NotificationType } from "@/domain/entities/notificationEntity";

export class CreatorSubscriptionWebhookUseCase implements ICreatorSubscriptionWebhookUseCase {
    constructor(
        private _creatorRepo: ICreatorRepository,
        private _subscriptionRepo: ISubscriptionRepository,
        private _stripeService: IStripeService,
        private _mailService: IMailService,
        private _creditWalletUseCase: ICreditWalletUseCase,
        private _sendNotificationUseCase: ISendNotificationUseCase,
        private _userRepo: IUserRepository
    ) {}

    async handle(payload: string | Buffer, signature: string) {
        const event = this._stripeService.constructEvent(payload, signature);
        await this.handleEvent(event);
    }

    async handleEvent(event: Stripe.Event) {
        if (event.type === "checkout.session.completed") {
            const session = event.data.object as Stripe.Checkout.Session;
            if (session.metadata?.type === "subscription") {
                const { creatorId, subscriptionId } = session.metadata;

                if (!creatorId || !subscriptionId) {
                    logger.warn("Webhook missing creatorId or subscriptionId");
                    return;
                }

                const plan = await this._subscriptionRepo.findById(subscriptionId);
                if (!plan) {
                    logger.warn("Subscription plan not found", { subscriptionId });
                    return;
                }

                const creator = await this._creatorRepo.findById(creatorId);

                const alreadyProcessed =
                    creator?.subscription?.stripeSessionId === session.id ||
                    creator?.upcomingSubscription?.stripeSessionId === session.id;
                if (alreadyProcessed) {
                    logger.info("Webhook already processed for this session", { sessionId: session.id });
                    return;
                }

                const now = new Date();
                const hasActiveSubscription =
                    creator?.subscription?.status === "active" &&
                    new Date(creator.subscription.endDate) > now;

                const logoAttachment = [{
                    filename: "Logo_white.png",
                    path: path.join(process.cwd(), "public", "Logo_white.png"),
                    cid: "phlo-logo",
                }];

                if (hasActiveSubscription) {
                    // Queue as upcoming — starts exactly when the current plan ends
                    const startDate = new Date(creator!.subscription!.endDate);
                    const endDate = new Date(startDate);
                    endDate.setDate(startDate.getDate() + plan.duration * 30);

                    await this._creatorRepo.updateProfile(creatorId, {
                        upcomingSubscription: {
                            planId: subscriptionId,
                            planName: plan.name,
                            status: "active",
                            startDate,
                            endDate,
                            stripeSessionId: session.id,
                        },
                    });
                    logger.info("Upcoming subscription queued", { creatorId, planName: plan.name });

                    const html = renderTemplate("subscriptionQueued.html", {
                        name: creator!.fullName,
                        planName: plan.name,
                        startDate: startDate.toLocaleDateString("en-IN", { day: "numeric", month: "long", year: "numeric" }),
                        endDate: endDate.toLocaleDateString("en-IN", { day: "numeric", month: "long", year: "numeric" }),
                    });
                    await this._mailService.sendMail(creator!.email, "Your Subscription Upgrade is Queued", html, logoAttachment);

                    // Credit Admin Wallet (Unified)
                    await this._creditAdminWallet(plan, creator, session.id);

                    // Send Notification to Creator
                    await this._sendNotificationUseCase.sendNotification({
                        recipientId: creatorId,
                        type: NotificationType.ACCOUNT,
                        title: "Subscription Queued",
                        message: `Your upgrade to ${plan.name} is queued and will start on ${startDate.toLocaleDateString()}`,
                        isRead: false
                    });

                    // Send Notification to Admin
                    const adminId = await this._userRepo.findAdminId();
                    if (adminId) {
                        await this._sendNotificationUseCase.sendNotification({
                            recipientId: adminId,
                            type: NotificationType.WALLET,
                            title: "Wallet Credit (Subscription Queued)",
                            message: `Admin wallet credited for ${creator?.fullName || 'Creator'} upgrade to ${plan.name} (Queued).`,
                            isRead: false
                        });
                    }
                } else {
                    // No active subscription — activate immediately
                    const startDate = now;
                    const endDate = new Date();
                    endDate.setDate(startDate.getDate() + plan.duration * 30);

                    await this._creatorRepo.updateProfile(creatorId, {
                        subscription: {
                            planId: subscriptionId,
                            planName: plan.name,
                            status: "active",
                            startDate,
                            endDate,
                            stripeSessionId: session.id,
                        },
                    });
                    logger.info("Creator subscription activated", { creatorId, planName: plan.name });

                    const html = renderTemplate("subscriptionActivated.html", {
                        name: creator!.fullName,
                        planName: plan.name,
                        endDate: endDate.toLocaleDateString("en-IN", { day: "numeric", month: "long", year: "numeric" }),
                    });
                    await this._mailService.sendMail(creator!.email, "Your Subscription is Now Active", html, logoAttachment);

                    // Credit Admin Wallet (Unified)
                    await this._creditAdminWallet(plan, creator, session.id);

                    // Send Notification to Creator
                    await this._sendNotificationUseCase.sendNotification({
                        recipientId: creatorId,
                        type: NotificationType.ACCOUNT,
                        title: "Subscription Activated",
                        message: `Your ${plan.name} subscription is now active!`,
                        isRead: false
                    });

                    // Send Notification to Admin
                    const adminId = await this._userRepo.findAdminId();
                    if (adminId) {
                        await this._sendNotificationUseCase.sendNotification({
                            recipientId: adminId,
                            type: NotificationType.WALLET,
                            title: "Wallet Credit (Subscription)",
                            message: `Admin wallet credited for ${creator?.fullName || 'Creator'} purchase of ${plan.name} subscription.`,
                            isRead: false
                        });
                    }
                }
            }
        }
    }

    private async _creditAdminWallet(plan: any, creator: any, sessionId: string) {
        try {
            logger.info("Attempting to credit admin wallet", {
                price: plan.price,
                planName: plan.name,
                creatorId: creator?._id
            });

            await this._creditWalletUseCase.creditWallet("admin", "admin", plan.price, {
                amount: plan.price,
                type: "credit",
                description: `Subscription purchase: ${plan.name} for ${creator?.fullName || 'Creator'}`,
                source: "subscription",
                sourceId: sessionId,
                relatedName: creator?.fullName || 'Creator'
            });
            logger.info("Admin wallet credited for subscription", { sessionId, amount: plan.price });
        } catch (error) {
            logger.error("Failed to credit admin wallet for subscription", {
                error: error instanceof Error ? { message: error.message, stack: error.stack } : error,
                sessionId,
                planPrice: plan?.price,
                planName: plan?.name
            });
        }
    }
}

import { IBookingRepository } from "@/domain/interface/repository/IBookingRepository";
import { IStripeService } from "@/domain/interface/service/IStripeService";
import { IBookingWebhookUseCase } from "@/domain/interface/user/booking/IBookingWebhookUseCase ";
import { ICreditWalletUseCase } from "@/domain/interface/wallet/ICreditWalletUseCase";
import { IPackageRepository } from "@/domain/interface/repository/IPackageRepository";
import { ICreatorRepository } from "@/domain/interface/repository/ICreatorRepository";
import { IUserRepository } from "@/domain/interface/repository/IUserRepository";
import { IChatRepository } from "@/domain/interface/repository/IChatRepository ";
import { BookingStatus } from "@/constants/bookingStatus";
import { logger } from "@/utils/logger";
import { ISendNotificationUseCase } from "@/domain/interface/notification/ISendNotificationUseCase";
import { NotificationType } from "@/domain/entities/notificationEntity";
import Stripe from "stripe";

export class BookingWebhookUseCase implements IBookingWebhookUseCase {
  constructor(
    private _bookingRepo: IBookingRepository,
    private _stripeService: IStripeService,
    private _packageRepo: IPackageRepository,
    private _creatorRepo: ICreatorRepository,
    private _creditWalletUseCase: ICreditWalletUseCase,
    private _chatRepo: IChatRepository,
    private _sendNotificationUseCase: ISendNotificationUseCase,
    private _userRepo: IUserRepository
  ) { }

  async handleWebhook(payload: string | Buffer, signature: string): Promise<void> {
    const event = this._stripeService.constructEvent(payload, signature);
    await this.handleEvent(event);
  }

  async handleEvent(event: Stripe.Event): Promise<void> {
    if (event.type === "checkout.session.completed") {
      const session = event.data.object as Stripe.Checkout.Session;
      const bookingId = session.metadata?.bookingId;
      if (bookingId) {
        const booking = await this._bookingRepo.findById(bookingId);
        if (booking && booking.status === BookingStatus.COMPLETED) {
          logger.info("Booking already completed", { bookingId });
          return;
        }
        await this._bookingRepo.updateStatus(bookingId, BookingStatus.COMPLETED);
        await (this._bookingRepo as any).updatePaymentStatus(bookingId, "held");

        // Credit Admin Wallet & Create Conversation
        if (booking) {
          const pkg = await this._packageRepo.findById(booking.packageId as string);
          if (pkg) {
            const creator = await this._creatorRepo.findById(pkg.creatorId as string);

            // 1. Credit Wallet
            await this._creditWalletUseCase.creditWallet("admin", "admin", booking.amount, {
              amount: booking.amount,
              type: "credit",
              description: `Booking payment: ${pkg.title} by ${creator?.fullName || 'Creator'}`,
              source: "booking",
              sourceId: bookingId,
              relatedName: creator?.fullName || 'Creator'
            });
            logger.info("Admin wallet credited for booking", { bookingId, amount: booking.amount });

            // 2. Create Conversation for the chat
            const existingConv = await this._chatRepo.getConversationByBooking(bookingId);
            if (!existingConv) {
              await this._chatRepo.createConversation({
                bookingId: bookingId as any,
                participants: [booking.userId as any, pkg.creatorId as any],
                lastMessage: "Booking confirmed! You can now start chatting.",
                lastMessageAt: new Date()
              });
              logger.info("Conversation created for new booking", { bookingId });
            }

            // 3. Send Notifications
            // To Creator
            const creatorId = typeof pkg.creatorId === 'string' ? pkg.creatorId : (pkg.creatorId as any)._id?.toString() || (pkg.creatorId as any).id?.toString();
            await this._sendNotificationUseCase.sendNotification({
              recipientId: creatorId,
              type: NotificationType.BOOKING,
              title: "New Booking",
              message: `You have a new booking for ${pkg.title}`,
              isRead: false
            });

            // To User
            const bookingUserId = typeof booking.userId === 'string' ? booking.userId : (booking.userId as any)._id?.toString() || (booking.userId as any).id?.toString();
            await this._sendNotificationUseCase.sendNotification({
              recipientId: bookingUserId,
              type: NotificationType.BOOKING,
              title: "Booking Confirmed",
              message: `Your booking for ${pkg.title} has been confirmed`,
              isRead: false
            });

            // To Admin
            const adminId = await this._userRepo.findAdminId();
            if (adminId) {
              await this._sendNotificationUseCase.sendNotification({
                recipientId: adminId,
                type: NotificationType.WALLET,
                title: "Wallet Credit (Booking)",
                message: `Admin wallet credited ₹${booking.amount} for ${creator?.fullName || 'Creator'}'s package booking`,
                isRead: false
              });
            }
          }
        }

        logger.info("Booking completed via webhook", { bookingId });
      }
    }
  }
}

import { BookingMapper } from "@/application/mapper/user/bookingMapper";
import { BookingResponseDTO } from "@/domain/dto/booking/bookingResponseDto";
import { BookingEntity } from "@/domain/entities/bookingEntity";
import { AppError } from "@/domain/errors/appError";
import { IBookingRepository } from "@/domain/interface/repository/IBookingRepository";
import { ICancelBookingUseCase } from "@/domain/interface/user/booking/ICancelBookingUseCase";
import { BookingStatus } from "@/constants/bookingStatus";
import { StatusCode } from "@/constants/statusCodes";

import { IPackageRepository } from "@/domain/interface/repository/IPackageRepository";
import { ISendNotificationUseCase } from "@/domain/interface/notification/ISendNotificationUseCase";
import { NotificationType } from "@/domain/entities/notificationEntity";

import { IWalletRepository } from "@/domain/interface/repository/IWalletRepository";

export class CancelBookingUseCase implements ICancelBookingUseCase {
  constructor(
    private _bookingRepo: IBookingRepository,
    private _packageRepo: IPackageRepository,
    private _sendNotificationUseCase: ISendNotificationUseCase,
    private _walletRepo: IWalletRepository
  ) { }
  async cancelBooking(userId: string, sessionId: string): Promise<BookingResponseDTO> {
    const booking = await this._bookingRepo.findByStripeSessionId(sessionId)
    if (!booking) throw new Error("Booking not found")
    const bookingUserId = typeof booking.userId === 'string' ? booking.userId : (booking.userId as unknown as Record<string, unknown>)._id?.toString() || (booking.userId as unknown as Record<string, unknown>).id?.toString();
    if (bookingUserId !== userId) {
      throw new AppError("Unauthorized", StatusCode.UNAUTHORIZED);
    }
    if (booking.status !== BookingStatus.PENDING && booking.status !== BookingStatus.COMPLETED) {
      throw new AppError("Booking cannot be cancelled in its current state", StatusCode.BAD_REQUEST);
    }

    // Refund Logic (Updated):
    // 1. 100% Refund (Grace Period): If cancelled within 24 hours of MAKING the booking.
    // 2. 50% Refund: If cancelled more than 5 days (120h) BEFORE the booking date.
    // 3. No Refund: If cancelled less than 5 days (120h) before.
    
    const now = new Date();
    const createdAt = new Date(booking.createdAt || now);
    const bookingDate = new Date(booking.bookingDate);
    
    // Check Grace Period (24h from creation)
    const creationDiffH = (now.getTime() - createdAt.getTime()) / (1000 * 3600);
    const isWithinGracePeriod = creationDiffH <= 24;

    // Check Session Cutoff (5 days before session)
    const sessionDiffH = (bookingDate.getTime() - now.getTime()) / (1000 * 3600);
    const isBeforeSessionCutoff = sessionDiffH >= 120;

    let refundAmount = 0;
    let refundPercentage = 0;
    let refundReason = "";
    
    if (booking.status === BookingStatus.COMPLETED) {
      if (isWithinGracePeriod) {
        refundPercentage = 100;
        refundAmount = booking.amount;
        refundReason = "within 24h grace period from booking creation";
      } else if (isBeforeSessionCutoff) {
        refundPercentage = 50;
        refundAmount = Math.round(booking.amount * 0.5);
        refundReason = "before 5-day session cutoff";
      } else {
        refundReason = "after session cutoff and outside grace period";
      }
    }

    if (refundAmount > 0) {
      const bookingIdStr = (booking.id || (booking as any)._id) as string;
      
      // 1. Debit Admin Wallet
      await this._walletRepo.updateBalance("admin", "admin", -refundAmount, {
        amount: refundAmount,
        type: "debit",
        description: `Refund (${refundPercentage}%) for booking ${bookingIdStr} - ${refundReason}`,
        source: "booking",
        sourceId: bookingIdStr,
        relatedName: "user_refund"
      });

      // 2. Credit User Wallet
      await this._walletRepo.updateBalance(userId, "user", refundAmount, {
        amount: refundAmount,
        type: "credit",
        description: `Refund (${refundPercentage}%) for booking ${bookingIdStr} - ${refundReason}`,
        source: "booking",
        sourceId: bookingIdStr,
      });

      await this._bookingRepo.updatePaymentStatus(booking.id!, refundPercentage === 100 ? "refunded" : "partially_refunded");
    }

    const updatedBooking = await this._bookingRepo.updateStatus(booking.id!, BookingStatus.CANCELLED);

    if (!updatedBooking) {
      throw new AppError("Failed to cancel booking", StatusCode.INTERNAL_SERVER_ERROR);
    }

    // Trigger Notifications
    const pkg = await this._packageRepo.findById(booking.packageId as string);
    if (pkg) {
      const creatorId = typeof pkg.creatorId === 'string' ? pkg.creatorId : (pkg.creatorId as any)._id?.toString() || (pkg.creatorId as any).id?.toString();

      // To Creator
      await this._sendNotificationUseCase.sendNotification({
        recipientId: creatorId,
        type: NotificationType.BOOKING,
        title: "Booking Cancelled",
        message: `A booking for ${pkg.title} has been cancelled by the user. ${refundAmount > 0 ? `Amount (${refundPercentage}%) refunded to user (${refundReason}).` : 'Payment held (cancellation after cutoff).'}`,
        isRead: false
      });

      // To User
      await this._sendNotificationUseCase.sendNotification({
        recipientId: userId,
        type: NotificationType.BOOKING,
        title: "Booking Cancelled",
        message: `Your booking for ${pkg.title} has been successfully cancelled. ${refundAmount > 0 ? `${refundPercentage}% refund (₹${refundAmount}) has been initiated to your wallet (${refundReason}).` : 'Cancellation terms: No refund for cancellations within 5 days of the session.'}`,
        isRead: false
      });
    }

    return BookingMapper.toDto(updatedBooking);
  }

}

import { CheckoutSessionResponseDTO } from "@/domain/dto/payment/checkoutSessionResponseDto";
import { AppError } from "@/domain/errors/appError";
import { IBookingRepository } from "@/domain/interface/repository/IBookingRepository";
import { IPackageRepository } from "@/domain/interface/repository/IPackageRepository";
import { IStripeService } from "@/domain/interface/service/IStripeService";
import { IRetryPaymentUseCase } from "@/domain/interface/user/booking/IRetryPaymentUseCase";
import { BookingStatus } from "@/constants/bookingStatus";
import { StatusCode } from "@/constants/statusCodes";
import { CreatorEntity } from "@/domain/entities/creatorEntities";

export class RetryPaymentUseCase implements IRetryPaymentUseCase {
    constructor(
        private _bookingRepo: IBookingRepository,
        private _packageRepo: IPackageRepository,
        private _stripeService: IStripeService
    ) { }

    async retryPayment(sessionId: string, baseUrl: string): Promise<CheckoutSessionResponseDTO> {
        const booking = await this._bookingRepo.findByStripeSessionId(sessionId);
        if (!booking) {
            throw new AppError("Booking not found", StatusCode.NOT_FOUND);
        }

        if (booking.status !== BookingStatus.PENDING) {
            throw new AppError(`Booking status is ${booking.status}. Payment is not required.`, StatusCode.BAD_REQUEST);
        }

        const pkgId = typeof booking.packageId === 'string' ? booking.packageId : (booking.packageId as any)._id.toString();
        const pkg = await this._packageRepo.findById(pkgId);
        if (!pkg) {
            throw new AppError("Package details not found", StatusCode.NOT_FOUND);
        }

        const creatorId = typeof pkg.creatorId === "string"
            ? pkg.creatorId
            : (pkg.creatorId as CreatorEntity)._id?.toString() || "";

        const session = await this._stripeService.createCheckoutSession({
            bookingId: booking.id!,
            creatorId: creatorId,
            packageName: pkg.title,
            amount: pkg.price,
            successUrl: `${baseUrl}/payment-success?session_id={CHECKOUT_SESSION_ID}`,
            cancelUrl: `${baseUrl}/payment-cancel?booking_id=${booking.id}`,
            type: "booking",
            userId: typeof booking.userId === 'string' ? booking.userId : (booking.userId as any)._id.toString(),
        });

        // Update booking with the NEW stripeSessionId
        await this._bookingRepo.update(booking.id!, {
            stripeSessionId: session.id,
        });

        return session;
    }
}

